SELECT COUNT(*) AS QUANTIDADE FROM CALC_HORA_AULA_MEDIA CHAM JOIN SERVIDOR S ON S.PK_SIAPE = CHAM.SIAPE JOIN CURSO C ON LOWER(C.SIGLA) = LOWER(CHAM.SIGLA_CURSO) WHERE LOWER(CHAM.AREA_INGRESSO) LIKE '%administra%' AND LOWER(S.GENERO) = 'feminino' AND LOWER(CHAM.SIGLA_CAMPUS) = 'gyn' AND LOWER(C.NIVEL) = 'pos-graduacao lato sensu' AND CHAM.ANO >= (CAST(strftime('%Y', 'now') AS INTEGER) - 4)